SELECT DISTINCT library_name, library_release, source 
FROM libraries 
WHERE data_type = 'proteomic';

SELECT user_name, role
FROM users
WHERE role = 'researcher';

SELECT COUNT(*)
FROM query_gene
WHERE gene_id = 0;

SELECT COUNT(queries.query_id) AS query_count
FROM queries
INNER JOIN query_library ON queries.query_id = query_library.query_id;

SELECT query_id, project_id
FROM queries
WHERE data_format = 'FASTA';
